import React, { useState, useEffect } from 'react';
import Wavify from 'react-wavify';
import '../styles/Home.css';

function Home() {
  const [isSpeaking, setIsSpeaking] = useState(false);

  // This function will simulate fetching audio response and toggling wave animation
  const handleSpeak = () => {
    setIsSpeaking(true);
    // Simulate audio fetching from OpenAI with a timeout
    setTimeout(() => {
      setIsSpeaking(false);
    }, 5000); // Adjust based on actual response time
  };

  return (
    <div className="home-container">
      <div className="animated-background"></div>
      <h1 className="home-heading patrick-hand-regular">26Coach</h1>
      <h3 className="home-subheading patrick-hand-regular">THE MARATHON COACH THAT LIVES IN YOUR AIRPODS</h3>
      <img src="/images/runner-ai-generated.jpg" alt="Demo" className="demo-image" />
      <div className="cta-container">
        <button 
          onClick={handleSpeak} 
          className={`cta-button ${isSpeaking ? 'pulse' : ''}`}
        >
          Speak to 26Coach
        </button>
      </div>
      <div className="wave-container">
        {isSpeaking && (
          <Wavify 
            fill="#f7f7f7"
            paused={false}
            options={{
              height: 20,
              amplitude: 40,
              speed: 0.2,
              points: 3,
            }}
          />
        )}
      </div>
    </div>
  );
}

export default Home;
